function upsertRequestRows(rows, requestId, nextRows) {
  const base = Array.isArray(rows) ? rows.filter((item) => item.request_id !== requestId) : [];
  return base.concat(nextRows);
}

function slugify(value) {
  return String(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

